#!/usr/bin/env bash
# mdvs search-nudge hook for Claude Code (PostToolUse, Bash).
#
# Fires on any Bash invocation. If the agent's cwd (from stdin) is inside
# an mdvs vault AND the command is a search-style tool, emit a tip pointing
# at `mdvs search` as a structured alternative.
#
# The hook is non-blocking and informational only — exits 0 unconditionally.
#
# Requirements: `jq` on PATH.
#
# Generated by `mdvs scaffold hook --platform claude-code`.

set -euo pipefail

# Read the full stdin payload once (we need both .cwd and .tool_input.command).
payload=$(cat)

# Walk up from the cwd (sent by the harness in stdin) to find mdvs.toml.
# If no vault is reachable from cwd, the hook stays silent — no nudges
# outside an mdvs project.
cwd=$(printf '%s' "$payload" | jq -r '.cwd // empty')
[ -z "$cwd" ] && cwd=$(pwd)
d="$cwd"
while [ "$d" != "/" ] && [ ! -f "$d/mdvs.toml" ]; do
  d=$(dirname "$d")
done
[ ! -f "$d/mdvs.toml" ] && exit 0

# Only fire on search-style tool commands.
cmd=$(printf '%s' "$payload" | jq -r '.tool_input.command // empty')
case "$cmd" in
  *grep*|*rg\ *|*find\ *|*fd\ *|*ag\ *|*ack\ *|*"git grep"*) ;;
  *) exit 0 ;;
esac

# Emit the tip as additionalContext (model-visible, non-blocking).
jq -n \
  '{hookSpecificOutput: {hookEventName: "PostToolUse",
    additionalContext: "Tip: `mdvs search` is also available for semantic / hybrid / SQL-filtered search over the KB."}}'
